const original = $('Build Lead Data').item.json;

let aiText =
  $json.choices?.[0]?.message?.content ||
  $json.output ||
  $json.text ||
  $json.response ||
  "";

let parsed = {};

try {
  aiText = aiText
    .replace(/```json/g, "")
    .replace(/```/g, "")
    .trim();

  parsed = JSON.parse(aiText);
} catch (error) {
  parsed = {
    business_name: "Unknown",
    business_type: "Unknown",
    selected_service: original.selected_service,
    requirement_summary: original.requirements,
    main_problem: "Could not parse AI response",
    suggested_solution: "Manual review required",
    budget_signal: "unknown",
    urgency: "unknown",
    missing_fields: ["Manual review required"],
    lead_quality: "medium",
    follow_up_question: "Can you share a few more details about your requirement?"
  };
}

return [
  {
    json: {
      ...original,

      business_name: parsed.business_name || "Unknown",
      business_type: parsed.business_type || "Unknown",
      ai_selected_service: parsed.selected_service || original.selected_service,
      requirement_summary: parsed.requirement_summary || original.requirements,
      main_problem: parsed.main_problem || "Unknown",
      suggested_solution: parsed.suggested_solution || "Unknown",
      budget_signal: parsed.budget_signal || "unknown",
      urgency: parsed.urgency || "unknown",
      missing_fields: parsed.missing_fields || [],
      lead_quality: parsed.lead_quality || "medium",
      follow_up_question: parsed.follow_up_question || "",

      ai_processed: true,
      updated_at: new Date().toISOString()
    }
  }
];

