parameters.jsCode:
let outer = $json;

// In this case, AI Lead Brain returns everything inside "data" as text
if (typeof $json.data === "string") {
  try {
    outer = JSON.parse($json.data);
  } catch (e) {
    outer = {};
  }
}

const raw =
  outer.choices?.[0]?.message?.content ||
  $json.choices?.[0]?.message?.content ||
  "";

if (!raw) {
  return [{
    json: {
      service: "Unknown",
      business_type: "Unknown",
      requirement: "Could not parse AI response",
      urgency: "Unknown",
      lead_quality: "Cold",
      client_reply: "Thanks for reaching out to TechExon. Could you please share what service you need — website, automation, CRM, WhatsApp bot, or cybersecurity audit?",
      admin_summary: "AI response was empty or not in expected format."
    }
  }];
}

let parsed = {};

try {
  parsed = JSON.parse(raw);
} catch (e) {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  }
}

return [{
  json: {
    service: parsed.service || "Unknown",
    business_type: parsed.business_type || "Unknown",
    requirement: parsed.requirement || "Unknown",
    urgency: parsed.urgency || "Unknown",
    lead_quality: parsed.lead_quality || "Cold",
    client_reply: parsed.client_reply || "Thanks for reaching out to TechExon. Could you please share a few more details about your requirement?",
    admin_summary: parsed.admin_summary || "No admin summary generated."
  }
}];
